import{_ as r,o as t,c as _,j as a,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"鲑鱼结晶和光明会会员卡","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/鲑鱼结晶和光明会会员卡.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/鲑鱼结晶和光明会会员卡.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/鲑鱼结晶和光明会会员卡.md"};function l(d,e,p,i,c,h){return t(),_("div",null,[...e[0]||(e[0]=[a("h1",{id:"鲑鱼结晶和光明会会员卡",tabindex:"-1"},[s("鲑鱼结晶和光明会会员卡 "),a("a",{class:"header-anchor",href:"#鲑鱼结晶和光明会会员卡","aria-label":'Permalink to "鲑鱼结晶和光明会会员卡"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),n('<h1 id="鲑鱼结晶和光明会会员卡-1" tabindex="-1">鲑鱼结晶和光明会会员卡 <a class="header-anchor" href="#鲑鱼结晶和光明会会员卡-1" aria-label="Permalink to &quot;鲑鱼结晶和光明会会员卡&quot;">​</a></h1><p>鲑鱼的智慧结晶<br> D+500<br> 出自凯尔特神话相关传说，购买后在指定的一处部位生成1/2平方厘米的白色结晶，轮回者在舔舐该结晶一分钟后的下一次使用智力的检定获得+2的器械加值，以及1点附加成功，持续15分钟，同时只能有一个轮回者享受这一好处，而且无法叠加效果。</p><p>注：一直保持舔舐只能保证在附加成功结算后立即开始下一分钟的舔舐计算。<br> 注2：建议不要塞到一般舔不到的部位。</p><p>光明会会员卡<br> 10<br> 购买后，在每天早上八点，在轮回者所在地20米附近的合适的类信箱生成3瓶500ml的玻璃瓶装光明牛奶。如果没有类似空间，则生成在轮回者所在地20米附近的未被占用的地点。<br> 有些无良主神会将牛奶换为伊丽，蒙午等品牌，请注意甄别。</p><p>光明会超级会员卡<br> D+500<br> 需从光明会会员卡升级来，购买后，在每天早上八点，在轮回者所在地20米附近的合适的类信箱生成3瓶500ml的玻璃瓶装具有魔幻本质的超级牛奶。饮用至少500ml超级牛奶一次后，轮回者的下一次互动技能检定拥有一个临时+1的附加成功，该途径获得的临时成功可以叠加，持续一个场景。<br> 超级牛奶可以被指定为任何口味，但不影响其本质。如果没有类似空间，则生成在轮回者所在地20米附近的未被占用的地点。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const f=r(o,[["render",l]]);export{m as __pageData,f as default};
